                if (matrix[i][j] < minRow[i]) {
                    minRow[i] = matrix[i][j];
                }
            }
        }
        int[] maxCol = new int[C];
        for (int j = 0; j < C; j++) {
            maxCol[j] = Integer.MIN_VALUE;
            for (int i = 0; i < R; i++) {
                if (matrix[i][j] > maxCol[j]) {
                    maxCol[j] = matrix[i][j];
                }
            }
        }
        int result = -1;
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                if (matrix[i][j] == minRow[i] && matrix[i][j] == maxCol[j]) {
